using System;
using System.Diagnostics;
using System.IO;
using System.Runtime.InteropServices;
using SkiaSharp;
using SkiaSharp.HarfBuzz;

string fontFile = Path.Combine(Path.GetTempPath(), "test-font.ttf");
using (var typeface = SKTypeface.Default) {
    int idx;
    using var origStream = typeface.OpenStream(out idx);
    var len = origStream.Length;
    var bytes = new byte[len];
    var handle = GCHandle.Alloc(bytes, GCHandleType.Pinned);
    origStream.Read(handle.AddrOfPinnedObject(), len);
    handle.Free();
    File.WriteAllBytes(fontFile, bytes);
}
using (var fs = new SKFileStream(fontFile))
    Console.WriteLine($"GetMemoryBase: {(fs.GetMemoryBase() == IntPtr.Zero ? "Zero (else/LEAK)" : "non-zero")}");

GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect();
var proc = Process.GetCurrentProcess(); proc.Refresh();
long baseline = proc.WorkingSet64;
for (int i = 0; i < 1000; i++) {
    var fileStream = new SKFileStream(fontFile);
    using var blob = fileStream.ToHarfBuzzBlob();
}
proc.Refresh();
Console.WriteLine($"Else branch delta: {(proc.WorkingSet64 - baseline) / 1024} KB");

GC.Collect(); GC.WaitForPendingFinalizers(); GC.Collect();
proc.Refresh(); long ctrlBase = proc.WorkingSet64;
using (var tf = SKTypeface.Default) {
    for (int i = 0; i < 1000; i++) {
        int idx; var stream = tf.OpenStream(out idx);
        using var blob = stream.ToHarfBuzzBlob();
    }
}
proc.Refresh();
Console.WriteLine($"If branch delta: {(proc.WorkingSet64 - ctrlBase) / 1024} KB");
File.Delete(fontFile);
